"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { motion, AnimatePresence, useScroll, useMotionValueEvent } from "framer-motion";
import { Menu, X, ArrowUpRight } from "lucide-react";
import clsx from "clsx";

/**
 * NAV LINKS
 * SEO-friendly and localized for Sinan MC's brand
 */
type NavLink = { name: string; href: string; isNew?: boolean };

const navLinks: NavLink[] = [
    { name: "Home", href: "/" },
    { name: "About", href: "/about" },
    { name: "Portfolio", href: "/portfolio", isNew: true },
    { name: "Blog", href: "/blog" },
    { name: "Contact", href: "/contact" },
];

/**
 * LUXURY NAVBAR COMPONENT
 * Features: Floating pill, Glassmorphism, Gold accents, Scroll-to-hide, Smooth animations, SEO Structured Data, A11y Focus States
 */
export default function Navbar() {
    const pathname = usePathname();
    const [mounted, setMounted] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const [hidden, setHidden] = useState(false);
    const { scrollY } = useScroll();

    // Prevent layout shift by only rendering after mount
    useEffect(() => {
        setMounted(true);
    }, []);

    // Scroll Logic: Hide on scroll down, Show on scroll up
    useMotionValueEvent(scrollY, "change", (latest) => {
        const previous = scrollY.getPrevious() ?? 0;
        if (latest > previous && latest > 150) {
            setHidden(true);
        } else {
            setHidden(false);
        }
    });

    // Body Lock for Mobile Menu
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = "hidden";
        } else {
            document.body.style.overflow = "unset";
        }
    }, [isOpen]);

    // Close menu on route change
    useEffect(() => {
        setIsOpen(false);
    }, [pathname]);

    if (!mounted) return null;

    return (
        <header
            role="banner"
            itemScope
            itemType="http://schema.org/WPHeader"
            className="fixed top-0 inset-x-0 z-[100] flex justify-center w-full px-4 sm:px-6 pt-6 pointer-events-none"
        >
            <motion.nav
                role="navigation"
                aria-label="Main navigation"
                itemScope
                itemType="http://schema.org/SiteNavigationElement"
                initial={{ y: -100, opacity: 0 }}
                variants={{
                    visible: { y: 0, opacity: 1, scale: 1 },
                    hidden: { y: "-150%", opacity: 0, scale: 0.95 },
                }}
                animate={hidden && !isOpen ? "hidden" : "visible"}
                transition={{ duration: 0.7, ease: [0.22, 1, 0.36, 1] }}
                className={clsx(
                    "pointer-events-auto",
                    "flex items-center justify-between w-full max-w-4xl px-4 py-3 sm:px-6 lg:px-8",
                    "bg-[#09090b]/80 backdrop-blur-3xl border border-white/5 rounded-2xl",
                    "shadow-[0_8px_32px_rgba(0,0,0,0.5)] hover:shadow-[0_8px_32px_rgba(255,215,0,0.1)] hover:border-white/10 transition-all duration-500"
                )}
            >
                {/* LOGO: SINAN MC */}
                <Link
                    href="/"
                    className="group relative flex items-center gap-1 font-bold text-xl tracking-tight text-white hover:opacity-90 transition-opacity focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FFD700] rounded-lg px-2 py-1 -ml-2"
                    aria-label="Sinan MC Home"
                >
                    <span>SINAN</span>
                    <span className="text-[#FFD700] italic group-hover:drop-shadow-[0_0_8px_rgba(255,215,0,0.5)] transition-all">
                        MC
                    </span>
                </Link>

                {/* DESKTOP NAVIGATION */}
                <ul role="menubar" className="hidden md:flex items-center gap-1">
                    {navLinks.map((link) => {
                        const isActive = pathname === link.href || (link.href !== "/" && pathname.startsWith(link.href));

                        return (
                            <li key={link.href} role="none" className="relative">
                                <Link
                                    href={link.href}
                                    role="menuitem"
                                    itemProp="url"
                                    aria-current={isActive ? "page" : undefined}
                                    className={clsx(
                                        "relative z-10 px-4 py-2 text-sm font-medium transition-all duration-300 rounded-full focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FFD700] flex items-center group",
                                        isActive
                                            ? "text-[#0a0a0a]"
                                            : "text-white/70 hover:text-white hover:bg-white/5"
                                    )}
                                >
                                    {isActive && (
                                        <motion.div
                                            layoutId="nav-pill"
                                            className="absolute inset-0 bg-gradient-to-r from-[#FFD700] to-[#FDB931] rounded-full shadow-[0_0_20px_rgba(255,215,0,0.4)]"
                                            transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                                        />
                                    )}
                                    <span className="relative z-10 flex items-center gap-1.5" itemProp="name">
                                        {link.name}
                                        {link.isNew && (
                                            <span className="px-1.5 py-0.5 text-[9px] font-extrabold tracking-wider bg-gradient-to-r from-[#FFD700] to-[#FDB931] text-black rounded-full shadow-[0_0_10px_rgba(255,215,0,0.4)]">
                                                NEW
                                            </span>
                                        )}
                                    </span>
                                </Link>
                            </li>
                        );
                    })}
                </ul>

                {/* CALL TO ACTION */}
                <div className="flex items-center gap-3 sm:gap-4">
                    <Link
                        href="/contact"
                        aria-label="Contact and hire Sinan MC"
                        className={clsx(
                            "group hidden sm:flex items-center gap-2 px-6 py-2.5",
                            "bg-gradient-to-tr from-[#FFD700] via-[#FDB931] to-[#FFD700] text-[#0a0a0a] text-sm font-bold rounded-xl",
                            "shadow-[0_0_20px_rgba(255,215,0,0.3)]",
                            "hover:scale-[1.02] active:scale-[0.98] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FFD700] focus-visible:ring-offset-2 focus-visible:ring-offset-[#0a0a0a]",
                            "hover:shadow-[0_0_30px_rgba(255,215,0,0.5)] transition-all duration-300 ease-out overflow-hidden relative"
                        )}
                    >
                        {/* Shimmer Effect */}
                        <div className="absolute inset-0 -translate-x-full group-hover:animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-12" />

                        <span className="relative z-10">Hire Me</span>
                        <ArrowUpRight className="relative z-10 w-4 h-4 transition-transform group-hover:translate-x-0.5 group-hover:-translate-y-0.5" />
                    </Link>

                    {/* MOBILE HAMBURGER */}
                    <button
                        onClick={() => setIsOpen(!isOpen)}
                        aria-label={isOpen ? "Close menu" : "Open menu"}
                        aria-expanded={isOpen}
                        className="flex md:hidden items-center justify-center w-10 h-10 rounded-xl bg-white/5 border border-white/10 text-white active:scale-95 hover:bg-white/10 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FFD700] transition-all"
                    >
                        {isOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                    </button>
                </div>
            </motion.nav>

            {/* MOBILE FULLSCREEN MENU */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, backdropFilter: "blur(0px)" }}
                        animate={{ opacity: 1, backdropFilter: "blur(24px)" }}
                        exit={{ opacity: 0, backdropFilter: "blur(0px)" }}
                        transition={{ duration: 0.4 }}
                        className="fixed inset-0 z-[90] bg-gradient-to-b from-black/95 to-[#0a0a0a]/98 md:hidden overflow-hidden"
                    >
                        {/* Animated Background Orbs for Mobile Menu */}
                        <motion.div
                            initial={{ scale: 0.8, opacity: 0 }}
                            animate={{ scale: 1, opacity: 0.3 }}
                            transition={{ duration: 1 }}
                            className="absolute top-20 right-10 w-64 h-64 bg-[#FFD700] rounded-full mix-blend-screen filter blur-[100px]"
                        />

                        <div className="relative z-10 flex flex-col h-full mt-32 px-8">
                            <nav className="flex flex-col gap-6" aria-label="Mobile navigation">
                                {navLinks.map((link, idx) => {
                                    const isActive = pathname === link.href || (link.href !== "/" && pathname.startsWith(link.href));

                                    return (
                                        <motion.div
                                            key={link.href}
                                            initial={{ x: -40, opacity: 0 }}
                                            animate={{ x: 0, opacity: 1 }}
                                            transition={{ delay: 0.15 + idx * 0.1, type: "spring", stiffness: 100 }}
                                        >
                                            <Link
                                                href={link.href}
                                                itemProp="url"
                                                className={clsx(
                                                    "text-4xl font-bold tracking-tight transition-all flex items-center w-fit focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FFD700] rounded-xl px-4 py-2 -ml-4",
                                                    isActive ? "text-[#FFD700]" : "text-white/60 hover:text-white"
                                                )}
                                            >
                                                <span itemProp="name" className="flex items-center gap-3">
                                                    {link.name}
                                                    {link.isNew && (
                                                        <span className="px-2 py-0.5 text-[10px] font-extrabold tracking-wider bg-gradient-to-r from-[#FFD700] to-[#FDB931] text-black rounded-full shadow-[0_0_15px_rgba(255,215,0,0.4)]">
                                                            NEW
                                                        </span>
                                                    )}
                                                </span>
                                                {isActive && (
                                                    <motion.span
                                                        layoutId="mobile-dot"
                                                        className="inline-block ml-4 w-3 h-3 bg-[#FFD700] rounded-full shadow-[0_0_10px_rgba(255,215,0,0.8)]"
                                                    />
                                                )}
                                            </Link>
                                        </motion.div>
                                    );
                                })}
                            </nav>

                            <motion.div
                                className="mt-12 mb-10"
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: 0.2 + navLinks.length * 0.1 + 0.1 }}
                            >
                                <hr className="border-white/10 mb-8 w-1/3" />
                                <Link
                                    href="/contact"
                                    className="inline-flex items-center gap-2 text-2xl font-bold text-[#FFD700] group focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#FFD700] rounded-xl px-4 py-2 -ml-4"
                                    aria-label="Start a project with Sinan MC"
                                >
                                    Start a Project
                                    <ArrowUpRight className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                                </Link>
                                <p className="mt-2 ml-4 text-white/40 text-lg">
                                    Let&apos;s build something extraordinary together.
                                </p>
                            </motion.div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </header>
    );
}

"use client";

import { motion } from "framer-motion";
import Image from "next/image";
import Link from "next/link";
import {
    ArrowRight,
    GraduationCap,
    Briefcase,
    Award,
    Zap,
    CheckCircle2,
    Star,
    Wrench,
    Users,
    TrendingUp,
    Search,
    BarChart3,
    FileText,
    Cpu,
    ShieldCheck,
    Rocket,
    Target,
    Code2,
    Bot,
    Smartphone,
} from "lucide-react";

/* ─── Shared transition presets ─── */
const T_DEFAULT = { duration: 0.7, ease: [0.25, 0.1, 0.25, 1] as const };
const T_SLOW = { duration: 1, ease: [0.25, 0.1, 0.25, 1] as const };

/* ─── Wrapper that reveals on scroll using intersection observer ─── */
function Reveal({
    children,
    delay = 0,
    fromLeft = false,
    fromRight = false,
    className = "",
}: {
    children: React.ReactNode;
    delay?: number;
    fromLeft?: boolean;
    fromRight?: boolean;
    className?: string;
}) {
    const xVal = fromLeft ? -40 : fromRight ? 40 : 0;
    return (
        <motion.div
            className={className}
            initial={{ opacity: 0, x: xVal, y: xVal === 0 ? 30 : 0 }}
            whileInView={{ opacity: 1, x: 0, y: 0 }}
            viewport={{ once: true, margin: "-80px" }}
            transition={{ ...T_DEFAULT, delay }}
        >
            {children}
        </motion.div>
    );
}

/* ─── Staggered list ─── */
function StaggerList({ children }: { children: React.ReactNode }) {
    return (
        <motion.ul
            className="space-y-3"
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: "-80px" }}
            variants={{
                hidden: {},
                visible: { transition: { staggerChildren: 0.1 } },
            } as import("framer-motion").Variants}
        >
            {children}
        </motion.ul>
    );
}

/* ─── Animated list item ─── */
function ListItem({ text }: { text: string }) {
    return (
        <motion.li
            variants={{
                hidden: { opacity: 0, x: -16 },
                visible: { opacity: 1, x: 0, transition: { duration: 0.5 } },
            } as import("framer-motion").Variants}
            className="flex items-center gap-2.5 text-sm sm:text-base text-gray-300"
        >
            <CheckCircle2 className="shrink-0 w-4 h-4 text-primary" />
            {text}
        </motion.li>
    );
}

/* ─── Section overline label ─── */
function SectionLabel({ children }: { children: React.ReactNode }) {
    return (
        <span className="inline-block text-xs font-bold tracking-[0.25em] text-primary uppercase mb-3">
            {children}
        </span>
    );
}

/* ─── Animated gold line ─── */
function GoldLine() {
    return (
        <div className="relative h-[2px] w-20 my-4 overflow-hidden rounded-full bg-white/5">
            <motion.div
                className="absolute inset-y-0 left-0 w-full bg-gradient-to-r from-primary via-accent to-secondary"
                animate={{ x: ["-100%", "100%"] }}
                transition={{ repeat: Infinity, duration: 2.4, ease: "easeInOut" }}
            />
        </div>
    );
}

/* ─── Two-column section layout ─── */
function TwoColSection({
    label,
    heading,
    children,
    className = "",
}: {
    label: string;
    heading: string;
    children: React.ReactNode;
    className?: string;
}) {
    return (
        <section className={`relative z-10 py-16 sm:py-24 lg:py-28 ${className}`}>
            <div className="container mx-auto px-5 sm:px-8 lg:px-12">
                <div className="grid grid-cols-1 lg:grid-cols-[280px_1fr] gap-12 lg:gap-20 items-start">
                    {/* Sticky left heading */}
                    <Reveal fromLeft className="lg:sticky lg:top-32">
                        <SectionLabel>{label}</SectionLabel>
                        <h2 className="text-3xl sm:text-4xl font-bold text-white leading-tight">
                            {heading}
                        </h2>
                        <GoldLine />
                    </Reveal>

                    {/* Right content */}
                    <div>{children}</div>
                </div>
            </div>
        </section>
    );
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
/*  MAIN PAGE COMPONENT                                     */
/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
export default function AboutPageClient() {
    return (
        <main className="bg-dark text-white overflow-hidden">

            {/* ══════ SECTION 1 — HERO ABOUT ══════ */}
            <section
                className="relative pt-32 pb-16 md:pt-40 md:pb-32 overflow-hidden"
                aria-label="About Sinan MC – Best Freelance Web Developer and SEO Specialist in Malappuram"
            >
                {/* Background effects */}
                <div className="absolute inset-0 bg-[radial-gradient(ellipse_60%_60%_at_50%_40%,rgba(255,215,0,0.05),transparent)] pointer-events-none" />
                <div className="absolute inset-0 opacity-[0.025] bg-noise pointer-events-none" />
                <div className="absolute top-1/4 left-0 w-[500px] h-[500px] bg-primary/5 rounded-full blur-[120px] -z-10 pointer-events-none" />
                <div className="absolute bottom-0 right-0 w-[600px] h-[600px] bg-accent/5 rounded-full blur-[150px] -z-10 pointer-events-none" />

                <div className="container mx-auto px-5 sm:px-8 lg:px-12">
                    <div className="flex flex-col lg:flex-row items-center justify-between gap-12 lg:gap-20">

                        {/* ── LEFT: Text panel ── */}
                        <div className="w-full lg:w-[55%] flex flex-col space-y-6 sm:space-y-8 z-10 order-2 lg:order-1">
                            <div>
                                {/* Overline */}
                                <motion.div
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ ...T_DEFAULT, delay: 0.3 }}
